import { useRef, useEffect, useState } from 'react';
import { renderTartanToCanvas } from '../utils/renderTartan';
import { WEAVE_PATTERNS } from '../core/weaves';
import type { WeaveType } from '../core/types';

const WEAVE_TYPES: WeaveType[] = [
  'plain',
  'twill-2-2',
  'twill-3-1',
  'herringbone',
  'houndstooth',
  'basketweave',
];

interface WeaveSelectorProps {
  threadcount: string;
  activeWeave: WeaveType;
  onChange: (weave: WeaveType) => void;
}

function WeaveThumb({
  threadcount,
  weaveType,
  isActive,
  onClick,
}: {
  threadcount: string;
  weaveType: WeaveType;
  isActive: boolean;
  onClick: () => void;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rendered, setRendered] = useState(false);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, threadcount, 120, weaveType);
      setRendered(true);
    }
  }, [threadcount, weaveType]);

  return (
    <button
      onClick={onClick}
      className={`flex-shrink-0 group transition-all duration-200 text-center
                  ${isActive ? '' : 'opacity-70 hover:opacity-100'}`}
    >
      <div
        className={`w-16 h-16 sm:w-20 sm:h-20 rounded-lg overflow-hidden border-2 transition-all duration-200
                    ${isActive
                      ? 'border-[var(--accent)] shadow-sm'
                      : 'border-[var(--border)] group-hover:border-[var(--border-hover)]'
                    }`}
      >
        {!rendered && <div className="w-full h-full animate-shimmer" />}
        <canvas
          ref={canvasRef}
          className={`w-full h-full ${rendered ? '' : 'opacity-0 absolute'}`}
          style={{ imageRendering: 'pixelated' }}
        />
      </div>
      <span className={`block mt-1.5 text-[10px] font-mono leading-tight transition-colors
                        ${isActive ? 'text-[var(--text)]' : 'text-[var(--text-tertiary)]'}`}>
        {WEAVE_PATTERNS[weaveType].name}
      </span>
    </button>
  );
}

export default function WeaveSelector({ threadcount, activeWeave, onChange }: WeaveSelectorProps) {
  return (
    <div>
      <h2 className="text-xs font-mono uppercase tracking-widest text-[var(--text-tertiary)] mb-3">
        Weave Structure
      </h2>
      <div className="flex gap-3 overflow-x-auto no-scrollbar pb-1">
        {WEAVE_TYPES.map((wt) => (
          <WeaveThumb
            key={wt}
            threadcount={threadcount}
            weaveType={wt}
            isActive={activeWeave === wt}
            onClick={() => onChange(wt)}
          />
        ))}
      </div>
    </div>
  );
}
